#!/usr/bin/env python3
"""Patch chat.tsx with context window indicators + compact button."""

FILE = "/home/dom/projects/pinchy/web/src/routes/chat.tsx"

with open(FILE, "r") as f:
    content = f.read()

original = content
applied = 0

def do_replace(label, old, new):
    global content, applied
    if old not in content:
        print(f"  SKIP {label} -- anchor not found")
        return False
    content = content.replace(old, new, 1)
    applied += 1
    print(f"  OK {label}")
    return True

